query:
{
  pods(
    where: {
      managerName: { eq: "" }
      OR: [
        {
          containers_SOME: {
            env_SOME: { isValueFromSet: { eq: true }, isSecretKeySelectorSet: { eq: true } }
          }
        }
        { NOT: { secretVolumes: { eq: [] } } }
      ]
    }
  ) {
    ...AssetFragment
  }
}
